import { CommonModule } from '@angular/common';
import { Component, OnInit } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { RouterLink } from '@angular/router';
import { EMPTY, catchError, distinctUntilChanged, filter, forkJoin, map, merge, of, skip, switchMap, tap, timeout, timer } from 'rxjs';
import { ApiService } from '../shared/services/api.service';
import { SessionService } from '../shared/services/session.service';
import { DataRefreshService } from '../shared/services/data-refresh.service';
import { NotificationMessage, RewardsAccount, TransactionItem, WalletBalanceResponse } from '../shared/models/app.models';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.scss'
})
export class DashboardComponent implements OnInit {
  loading = true;
  loadingError: string | null = null;
  balance = 0;
  rewards: RewardsAccount | null = null;
  recentTransactions: TransactionItem[] = [];
  recentNotifications: NotificationMessage[] = [];
  private currentUserId: number | null = null;
  private firstLoadCompleted = false;
  private requestInFlight = false;

  constructor(
    private readonly api: ApiService,
    private readonly session: SessionService,
    private readonly dataRefresh: DataRefreshService
  ) {
    // If user is already loaded in session, immediately start loading dashboard
    const existingUser = this.session.currentUser;
    if (existingUser?.userId && existingUser.userId > 0) {
      console.log(' [DASHBOARD] User already in session:', existingUser);
      this.currentUserId = existingUser.userId;
    }

    merge(
      this.dataRefresh.getTransactionsRefresh$,
      this.dataRefresh.getNotificationsRefresh$,
      this.dataRefresh.getBalanceRefresh$,
      this.dataRefresh.getGlobalRefresh$
    )
      .pipe(takeUntilDestroyed())
      .subscribe(() => {
        if (this.currentUserId != null && this.currentUserId > 0) {
          this.loadDashboardData(this.currentUserId);
        }
      });
  }

  ngOnInit(): void {
    console.log(' [DASHBOARD] Component initialized');

    // Add safety timeout to prevent infinite loading
    const loadingSafetyTimeout = setTimeout(() => {
      if (this.loading) {
        console.warn(' [DASHBOARD] Safety timeout - forcing loading to false after 10 seconds');
        this.loading = false;
        this.loadingError = 'Data is taking longer than expected. Showing default view.';
      }
    }, 10000);

    // If user is already available, load data immediately without waiting
    if (this.currentUserId && this.currentUserId > 0) {
      console.log(' [DASHBOARD] User already available, loading data immediately:', this.currentUserId);
      this.loading = true;
      this.loadDashboardData(this.currentUserId, true);
    }

    console.log(' [DASHBOARD] Subscribing to user$ observable...');

    this.session.user$
      .pipe(
        tap((user) => console.log(' [DASHBOARD] user$ emitted:', user)),
        map((user) => (user?.userId ?? null) as number | null),
        distinctUntilChanged(),
        tap((userId) => console.log(' [DASHBOARD] After map, userId:', userId)),
        filter((userId): userId is number => {
          const isValid = userId != null && Number.isFinite(userId) && userId > 0;
          console.log(` [DASHBOARD] Filter check: userId=${userId}, isValid=${isValid}`);
          if (!isValid) {
            console.warn(' [DASHBOARD] Invalid userId, filtering out:', userId);
            this.balance = 0;
            this.rewards = null;
            this.recentTransactions = [];
            this.recentNotifications = [];
            this.loading = false;
            this.loadingError = null;
          }
          return isValid;
        }),
        switchMap((userId: number) => {
          console.log(' [DASHBOARD] switchMap: Valid userId detected:', userId, '- Loading data immediately...');
          this.currentUserId = userId;
          this.firstLoadCompleted = false;
          this.requestInFlight = false;
          this.loadingError = null;

          // Load data IMMEDIATELY (tick=0), then repeat every 15 seconds
          return timer(0, 15000).pipe(
            map((tick) => ({
              userId,
              showLoader: tick === 0 && !this.firstLoadCompleted,
              tick
            })),
            timeout(45000)
          );
        }),
        catchError((err: any) => {
          console.error(' [DASHBOARD] Observable error:', err);
          this.loading = false;
          this.loadingError = 'Connection error. Please try again.';
          return EMPTY;
        }),
        takeUntilDestroyed()
      )
      .subscribe(
        ({ userId, showLoader, tick }: { userId: number; showLoader: boolean; tick: number }) => {
          console.log(` [DASHBOARD] Poll tick ${tick}: userId=${userId}, firstLoadCompleted=${this.firstLoadCompleted}, requestInFlight=${this.requestInFlight}, showLoader=${showLoader}`);
          this.loadDashboardData(userId, showLoader);
        },
        (err: any) => {
          console.error(' [DASHBOARD] Subscription error:', err);
          this.loading = false;
          this.loadingError = 'Failed to load dashboard';
        }
      );
  }

  private loadDashboardData(userIdFromSession?: number, showLoader = false): void {
    const userId = userIdFromSession ?? this.session.currentUser?.userId;
    console.log(` [DASHBOARD-LOAD] Starting load: userId=${userId}, showLoader=${showLoader}`);

    if (userId == null || !Number.isFinite(userId) || userId <= 0) {
      console.warn(' [DASHBOARD-LOAD] Invalid userId, aborting:', userId);
      this.loading = false;
      this.requestInFlight = false;
      return;
    }

    if (this.requestInFlight) {
      console.log(' [DASHBOARD-LOAD] Request already in flight, skipping');
      return;
    }

    this.requestInFlight = true;
    if (showLoader) {
      console.log(' [DASHBOARD-LOAD] Showing loader spinner');
      this.loading = true;
    }
    // Also show loader for subsequent refreshes after initial data is loaded
    // This provides visual feedback that data is being refreshed
    if (this.firstLoadCompleted && !this.loading) {
      console.log(' [DASHBOARD-LOAD] Showing loader for data refresh');
      this.loading = true;
    }

    console.log(' [DASHBOARD-LOAD] Fetching data from APIs...');

    forkJoin({
      balance: this.api.getWalletBalance(userId).pipe(
        timeout(9000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] Wallet balance error:', err.message);
          return of({ balance: 0 } as WalletBalanceResponse);
        })
      ),
      rewards: this.api.getRewardsSummary(userId).pipe(
        timeout(9000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] Rewards error:', err.message);
          return of({ points: 0, tier: 'SILVER' } as unknown as RewardsAccount);
        })
      ),
      transactions: this.api.getTransactionsByUser(userId).pipe(
        timeout(9000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] Transactions error:', err.message);
          return of([] as TransactionItem[]);
        })
      ),
      notifications: this.api.getNotificationHistory(userId).pipe(
        timeout(9000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] Notifications error:', err.message);
          return of([] as NotificationMessage[]);
        })
      )
    })
      .pipe(
        timeout(12000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] ForkJoin timeout or error:', err.message);
          return of({
            balance: { balance: 0 } as WalletBalanceResponse,
            rewards: { points: 0, tier: 'SILVER' } as unknown as RewardsAccount,
            transactions: [] as TransactionItem[],
            notifications: [] as NotificationMessage[]
          });
        }),
        takeUntilDestroyed()
      )
      .subscribe({
        next: (result) => {
          try {
            console.log('✅ [DASHBOARD-LOAD] Data received, processing...', result);
            this.balance = Number(result.balance?.balance || 0);
            this.rewards = result.rewards;
            this.recentTransactions = (result.transactions ?? []).slice(0, 5);
            this.recentNotifications = (result.notifications ?? []).slice(0, 5);
            this.firstLoadCompleted = true;
            this.loadingError = null;
            console.log('✅ [DASHBOARD-LOAD] Data processed: balance=' + this.balance + ', tx=' + this.recentTransactions.length + ', notif=' + this.recentNotifications.length);
          } catch (err) {
            console.error('Error processing dashboard data:', err);
            this.loadingError = 'Error processing data';
          } finally {
            this.requestInFlight = false;
            this.loading = false;
          }
        },
        error: (err) => {
          console.error('Dashboard subscription error:', err);
          this.requestInFlight = false;
          this.loading = false;
          this.loadingError = 'Failed to load data';
        }
      });
  }
}

import { CommonModule } from '@angular/common';
import { Component, OnInit } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { RouterLink } from '@angular/router';
import { EMPTY, catchError, distinctUntilChanged, filter, forkJoin, map, merge, of, skip, switchMap, tap, timeout, timer } from 'rxjs';
import { ApiService } from '../shared/services/api.service';
import { SessionService } from '../shared/services/session.service';
import { DataRefreshService } from '../shared/services/data-refresh.service';
import { NotificationMessage, RewardsAccount, TransactionItem, WalletBalanceResponse } from '../shared/models/app.models';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.scss'
})
export class DashboardComponent implements OnInit {
  loading = true;
  loadingError: string | null = null;
  balance = 0;
  rewards: RewardsAccount | null = null;
  recentTransactions: TransactionItem[] = [];
  recentNotifications: NotificationMessage[] = [];
  private currentUserId: number | null = null;
  private firstLoadCompleted = false;
  private requestInFlight = false;

  constructor(
    private readonly api: ApiService,
    private readonly session: SessionService,
    private readonly dataRefresh: DataRefreshService
  ) {
    // IMMEDIATE: If user is already loaded in session, start loading data RIGHT NOW
    const existingUser = this.session.currentUser;
    if (existingUser?.userId && existingUser.userId > 0) {
      console.log(' [DASHBOARD] Constructor: User already in session, loading data IMMEDIATELY:', existingUser);
      this.currentUserId = existingUser.userId;
      this.loading = true;
      // Start loading immediately in constructor, don't wait for ngOnInit
      this.loadDashboardData(this.currentUserId, true);
    } else {
      console.log(' [DASHBOARD] Constructor: No user in session yet');
    }

    merge(
      this.dataRefresh.getTransactionsRefresh$,
      this.dataRefresh.getNotificationsRefresh$,
      this.dataRefresh.getBalanceRefresh$,
      this.dataRefresh.getGlobalRefresh$
    )
      .pipe(takeUntilDestroyed())
      .subscribe(() => {
        if (this.currentUserId != null && this.currentUserId > 0) {
          this.loadDashboardData(this.currentUserId);
        }
      });
  }

  ngOnInit(): void {
    console.log(' [DASHBOARD] Component initialized');

    // Add safety timeout to prevent infinite loading
    const loadingSafetyTimeout = setTimeout(() => {
      if (this.loading) {
        console.warn(' [DASHBOARD] Safety timeout - forcing loading to false after 10 seconds');
        this.loading = false;
        this.loadingError = 'Data is taking longer than expected. Showing default view.';
      }
    }, 10000);

    // If user is already available, load data immediately without waiting
    if (this.currentUserId && this.currentUserId > 0) {
      console.log(' [DASHBOARD] User already available, loading data immediately:', this.currentUserId);
      this.loading = true;
      this.loadDashboardData(this.currentUserId, true);
    }

    console.log(' [DASHBOARD] Subscribing to user$ observable...');

    this.session.user$
      .pipe(
        tap((user) => console.log(' [DASHBOARD] user$ emitted:', user)),
        map((user) => (user?.userId ?? null) as number | null),
        distinctUntilChanged(),
        tap((userId) => console.log(' [DASHBOARD] After map, userId:', userId)),
        filter((userId): userId is number => {
          const isValid = userId != null && Number.isFinite(userId) && userId > 0;
          console.log(` [DASHBOARD] Filter check: userId=${userId}, isValid=${isValid}`);
          if (!isValid) {
            console.warn(' [DASHBOARD] Invalid userId, filtering out:', userId);
            this.balance = 0;
            this.rewards = null;
            this.recentTransactions = [];
            this.recentNotifications = [];
            this.loading = false;
            this.loadingError = null;
          }
          return isValid;
        }),
        switchMap((userId: number) => {
          console.log(' [DASHBOARD] switchMap: Valid userId detected:', userId, '- Loading data immediately...');
          this.currentUserId = userId;
          this.firstLoadCompleted = false;
          this.requestInFlight = false;
          this.loadingError = null;

          // Load data IMMEDIATELY (tick=0), then repeat every 15 seconds
          return timer(0, 15000).pipe(
            map((tick) => ({
              userId,
              showLoader: tick === 0 && !this.firstLoadCompleted,
              tick
            })),
            timeout(45000)
          );
        }),
        catchError((err: any) => {
          console.error(' [DASHBOARD] Observable error:', err);
          this.loading = false;
          this.loadingError = 'Connection error. Please try again.';
          return EMPTY;
        }),
        takeUntilDestroyed()
      )
      .subscribe(
        ({ userId, showLoader, tick }: { userId: number; showLoader: boolean; tick: number }) => {
          console.log(` [DASHBOARD] Poll tick ${tick}: userId=${userId}, firstLoadCompleted=${this.firstLoadCompleted}, requestInFlight=${this.requestInFlight}, showLoader=${showLoader}`);
          this.loadDashboardData(userId, showLoader);
        },
        (err: any) => {
          console.error(' [DASHBOARD] Subscription error:', err);
          this.loading = false;
          this.loadingError = 'Failed to load dashboard';
        }
      );
  }

  private loadDashboardData(userIdFromSession?: number, showLoader = false): void {
    const userId = userIdFromSession ?? this.session.currentUser?.userId;
    console.log(` [DASHBOARD-LOAD] Starting load: userId=${userId}, showLoader=${showLoader}`);

    if (userId == null || !Number.isFinite(userId) || userId <= 0) {
      console.warn(' [DASHBOARD-LOAD] Invalid userId, aborting:', userId);
      this.loading = false;
      this.requestInFlight = false;
      return;
    }

    if (this.requestInFlight) {
      console.log(' [DASHBOARD-LOAD] Request already in flight, skipping');
      return;
    }

    this.requestInFlight = true;
    if (showLoader) {
      console.log(' [DASHBOARD-LOAD] Showing loader spinner');
      this.loading = true;
    }
    // Also show loader for subsequent refreshes after initial data is loaded
    // This provides visual feedback that data is being refreshed
    if (this.firstLoadCompleted && !this.loading) {
      console.log(' [DASHBOARD-LOAD] Showing loader for data refresh');
      this.loading = true;
    }

    console.log(' [DASHBOARD-LOAD] Fetching data from APIs...');

    forkJoin({
      balance: this.api.getWalletBalance(userId).pipe(
        timeout(9000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] Wallet balance error:', err.message);
          return of({ balance: 0 } as WalletBalanceResponse);
        })
      ),
      rewards: this.api.getRewardsSummary(userId).pipe(
        timeout(9000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] Rewards error:', err.message);
          return of({ points: 0, tier: 'SILVER' } as unknown as RewardsAccount);
        })
      ),
      transactions: this.api.getTransactionsByUser(userId).pipe(
        timeout(9000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] Transactions error:', err.message);
          return of([] as TransactionItem[]);
        })
      ),
      notifications: this.api.getNotificationHistory(userId).pipe(
        timeout(9000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] Notifications error:', err.message);
          return of([] as NotificationMessage[]);
        })
      )
    })
      .pipe(
        timeout(12000),
        catchError((err) => {
          console.error('❌ [DASHBOARD-LOAD] ForkJoin timeout or error:', err.message);
          return of({
            balance: { balance: 0 } as WalletBalanceResponse,
            rewards: { points: 0, tier: 'SILVER' } as unknown as RewardsAccount,
            transactions: [] as TransactionItem[],
            notifications: [] as NotificationMessage[]
          });
        }),
        takeUntilDestroyed()
      )
      .subscribe({
        next: (result) => {
          try {
            console.log('✅ [DASHBOARD-LOAD] Data received, processing...', result);
            this.balance = Number(result.balance?.balance || 0);
            this.rewards = result.rewards;
            this.recentTransactions = (result.transactions ?? []).slice(0, 5);
            this.recentNotifications = (result.notifications ?? []).slice(0, 5);
            this.firstLoadCompleted = true;
            this.loadingError = null;
            console.log('✅ [DASHBOARD-LOAD] Data processed: balance=' + this.balance + ', tx=' + this.recentTransactions.length + ', notif=' + this.recentNotifications.length);
          } catch (err) {
            console.error('Error processing dashboard data:', err);
            this.loadingError = 'Error processing data';
          } finally {
            this.requestInFlight = false;
            this.loading = false;
          }
        },
        error: (err) => {
          console.error('Dashboard subscription error:', err);
          this.requestInFlight = false;
          this.loading = false;
          this.loadingError = 'Failed to load data';
        }
      });
  }
}

import { Injectable, inject } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { JwtUser } from '../models/app.models';
import { TokenStorageService } from './token-storage.service';

@Injectable({ providedIn: 'root' })
export class SessionService {
  // Use inject() so dependency is available during field initialization.
  private readonly tokenStorage = inject(TokenStorageService);
  private readonly userState = new BehaviorSubject<JwtUser | null>(this.readUserFromToken());
  readonly user$ = this.userState.asObservable();

  get currentUser(): JwtUser | null {
    return this.userState.value;
  }

  get token(): string | null {
    return this.tokenStorage.getToken();
  }

  isLoggedIn(): boolean {
    return !!this.currentUser;
  }

  hasRole(role: string): boolean {
    const currentRole = this.currentUser?.role || '';
    return currentRole.toUpperCase() === role.toUpperCase();
  }

  saveToken(token: string): void {
    console.log(' [SESSION] Saving token...');
    this.tokenStorage.setToken(token);
    const user = this.readUserFromToken();
    console.log(' [SESSION] Token saved, extracted user:', user);
    this.userState.next(user);
  }

  refreshFromStorage(): void {
    const user = this.readUserFromToken();
    console.log(' [SESSION] Refreshing from storage, user:', user);
    this.userState.next(user);
  }

  logout(): void {
    console.log(' [SESSION] Logging out...');
    this.tokenStorage.clear();
    this.userState.next(null);
  }

  private readUserFromToken(): JwtUser | null {
    const token = this.tokenStorage.getToken();
    if (!token) {
      console.warn(' [SESSION] No token found in storage');
      return null;
    }

    const parts = token.split('.');
    if (parts.length !== 3) {
      console.warn(' [SESSION] Invalid token format (not 3 parts)');
      return null;
    }

    try {
      const encodedPayload = parts[1].replace(/-/g, '+').replace(/_/g, '/');
      const paddedPayload = encodedPayload.padEnd(Math.ceil(encodedPayload.length / 4) * 4, '=');
      const payloadJson = atob(paddedPayload);
      const payload = JSON.parse(payloadJson) as Record<string, unknown>;

      console.log(' [SESSION] Token payload:', payload);

      const userIdRaw = payload['userId'] ?? payload['id'] ?? payload['uid'];
      const userId = typeof userIdRaw === 'number' ? userIdRaw : Number(userIdRaw);

      if (!Number.isFinite(userId) || userId <= 0) {
        console.warn(' [SESSION] Invalid userId extracted:', userIdRaw, 'parsed:', userId);
        return null;
      }

      const username = String(payload['sub'] ?? payload['username'] ?? '');
      const role = String(payload['role'] ?? '').toUpperCase();

      const user = { userId, username, role };
      console.log('✅ [SESSION] User extracted successfully:', user);
      return user;
    } catch (err) {
      console.error('❌ [SESSION] Error parsing token:', err);
      return null;
    }
  }
}

import { Injectable, inject } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { JwtUser } from '../models/app.models';
import { TokenStorageService } from './token-storage.service';

@Injectable({ providedIn: 'root' })
export class SessionService {
  // Use inject() so dependency is available during field initialization.
  private readonly tokenStorage = inject(TokenStorageService);
  private readonly userState = new BehaviorSubject<JwtUser | null>(this.readUserFromToken());
  readonly user$ = this.userState.asObservable();

  get currentUser(): JwtUser | null {
    return this.userState.value;
  }

  get token(): string | null {
    return this.tokenStorage.getToken();
  }

  isLoggedIn(): boolean {
    return !!this.currentUser;
  }

  hasRole(role: string): boolean {
    const currentRole = this.currentUser?.role || '';
    return currentRole.toUpperCase() === role.toUpperCase();
  }

  saveToken(token: string): void {
    console.log(' [SESSION] Saving token...');
    this.tokenStorage.setToken(token);
    const user = this.readUserFromToken();
    console.log(' [SESSION] Token saved, extracted user:', user);
    this.userState.next(user);
  }

  refreshFromStorage(): void {
    const user = this.readUserFromToken();
    console.log(' [SESSION] Refreshing from storage, user:', user);
    console.log(' [SESSION] Current state before next:', this.userState.value);
    // FORCE emit by setting to null first, then to user
    // This ensures BehaviorSubject emits even if previous value was null
    if (user && this.userState.value?.userId !== user.userId) {
      this.userState.next(user);
      console.log(' [SESSION] Emitted user:', user);
    } else if (user && !this.userState.value) {
      this.userState.next(user);
      console.log(' [SESSION] Emitted user (was null before):', user);
    } else {
      console.warn(' [SESSION] No new user to emit or same user already set');
    }
  }

  logout(): void {
    console.log(' [SESSION] Logging out...');
    this.tokenStorage.clear();
    this.userState.next(null);
  }

  private readUserFromToken(): JwtUser | null {
    const token = this.tokenStorage.getToken();
    if (!token) {
      console.warn(' [SESSION] No token found in storage');
      return null;
    }

    const parts = token.split('.');
    if (parts.length !== 3) {
      console.warn(' [SESSION] Invalid token format (not 3 parts)');
      return null;
    }

    try {
      const encodedPayload = parts[1].replace(/-/g, '+').replace(/_/g, '/');
      const paddedPayload = encodedPayload.padEnd(Math.ceil(encodedPayload.length / 4) * 4, '=');
      const payloadJson = atob(paddedPayload);
      const payload = JSON.parse(payloadJson) as Record<string, unknown>;

      console.log(' [SESSION] Token payload:', payload);

      const userIdRaw = payload['userId'] ?? payload['id'] ?? payload['uid'];
      const userId = typeof userIdRaw === 'number' ? userIdRaw : Number(userIdRaw);

      if (!Number.isFinite(userId) || userId <= 0) {
        console.warn(' [SESSION] Invalid userId extracted:', userIdRaw, 'parsed:', userId);
        return null;
      }

      const username = String(payload['sub'] ?? payload['username'] ?? '');
      const role = String(payload['role'] ?? '').toUpperCase();

      const user = { userId, username, role };
      console.log('✅ [SESSION] User extracted successfully:', user);
      return user;
    } catch (err) {
      console.error('❌ [SESSION] Error parsing token:', err);
      return null;
    }
  }
}

