  gap: 4px;
  text-align: left;
}

.full-width {
  width: 100%;
}

/* ─── Remember + Forgot row ─── */
.form-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}

.forgot-link {
  font-size: 13px;
  font-weight: 600;
  color: #667eea;
  cursor: pointer;
  text-decoration: none;

  &:hover {
    text-decoration: underline;
  }
}

/* ─── Error Alert ─── */
.error-alert {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 12px 16px;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 10px;
  color: #dc2626;
  font-size: 13px;
  margin-bottom: 16px;
  animation: fadeIn 0.3s ease;

  mat-icon {
    font-size: 20px;
    width: 20px;
    height: 20px;
  }
}

/* ─── Submit Button ─── */
.submit-btn {
  width: 100%;
  height: 48px;
  border-radius: 12px !important;
  font-size: 15px !important;
  font-weight: 700 !important;
  letter-spacing: 0.5px;
  text-transform: none !important;
  background: linear-gradient(135deg, #667eea, #764ba2) !important;
  color: #fff !important;
  box-shadow: 0 6px 20px rgba(102, 126, 234, 0.35) !important;
  transition: transform 0.15s ease, box-shadow 0.15s ease;

  &:hover:not([disabled]) {
    transform: translateY(-2px);
    box-shadow: 0 10px 28px rgba(102, 126, 234, 0.45) !important;
  }

  &:active {
    transform: scale(0.98);
  }
}

.btn-spinner {
  display: inline-block;
}

/* ─── Footer Link ─── */
.auth-footer {
  margin-top: 28px;
  font-size: 14px;
  color: #94a3b8;
}

.link {
  color: #667eea;
  font-weight: 700;
  text-decoration: none;
  cursor: pointer;

  &:hover {
    text-decoration: underline;
  }
}

/* ─── Animations ─── */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

/* ─── Responsive ─── */
@media (max-width: 480px) {
  .auth-card {
    padding: 32px 20px 28px;
    border-radius: 16px;
  }

  .auth-title {
    font-size: 24px;
  }
}

.auth-shell {
  animation: gradientShift 12s ease-in-out infinite alternate;
}

@keyframes gradientShift {
  from {
    filter: saturate(1);
  }

  to {
    filter: saturate(1.15);
  }
}



