        PaymentTransaction tx = new PaymentTransaction();
        LocalDateTime now = LocalDateTime.now().minusDays(1);
        tx.setCreatedAt(now);

        tx.onCreate();

        assertThat(tx.getCreatedAt()).isEqualTo(now);
    }
}

