package com.wallet.notification.security;

import io.jsonwebtoken.JwtException;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.io.Encoders;
import io.jsonwebtoken.security.Keys;
import org.junit.jupiter.api.Test;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

class JwtRoleValidatorTest {

    private static final String RAW_SECRET = "01234567890123456789012345678901";
    private static final String BASE64_SECRET = Encoders.BASE64.encode(RAW_SECRET.getBytes(StandardCharsets.UTF_8));

    @Test
    void extractRole_returnsUppercaseRole() {
        SecretKey key = Keys.hmacShaKeyFor(RAW_SECRET.getBytes(StandardCharsets.UTF_8));
        String token = Jwts.builder().claim("role", "support").signWith(key).compact();

        JwtRoleValidator validator = new JwtRoleValidator(BASE64_SECRET);

        assertThat(validator.extractRole(token)).isEqualTo("SUPPORT");
    }

    @Test
    void extractRole_withBlankToken_throwsJwtException() {
        JwtRoleValidator validator = new JwtRoleValidator(BASE64_SECRET);

        assertThatThrownBy(() -> validator.extractRole(" "))
                .isInstanceOf(JwtException.class)
                .hasMessageContaining("missing");
    }
}

package com.wallet.notification.service;

import com.wallet.notification.dto.NotificationEvent;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
class NotificationEventListenerTest {

    @Mock
    private NotificationService notificationService;

    @Test
    void onNotificationEvent_withValidEvent_delegatesToService() {
        NotificationEventListener listener = new NotificationEventListener(notificationService);

        listener.onNotificationEvent(new NotificationEvent(1L, "KYC", "email", "a@b.com", "approved"));

        verify(notificationService).send(any());
    }

    @Test
    void onNotificationEvent_withInvalidEvent_ignoresMessage() {
        NotificationEventListener listener = new NotificationEventListener(notificationService);

        listener.onNotificationEvent(new NotificationEvent(null, "KYC", "EMAIL", "x", "m"));

        verify(notificationService, never()).send(any());
    }

    @Test
    void onNotificationEvent_whenServiceThrows_swallowsException() {
        NotificationEventListener listener = new NotificationEventListener(notificationService);
        when(notificationService.send(any())).thenThrow(new RuntimeException("mail down"));

        listener.onNotificationEvent(new NotificationEvent(2L, "TOPUP", "SMS", "1234567890", "done"));

        verify(notificationService).send(any());
    }
}

package com.wallet.notification.service;

import com.wallet.notification.dto.DeviceTokenRequest;
import com.wallet.notification.dto.NotificationSendRequest;
import com.wallet.notification.dto.NotificationStatsResponse;
import com.wallet.notification.entity.DeviceToken;
import com.wallet.notification.entity.NotificationChannel;
import com.wallet.notification.entity.NotificationMessage;
import com.wallet.notification.entity.NotificationStatus;
import com.wallet.notification.repository.DeviceTokenRepository;
import com.wallet.notification.repository.NotificationMessageRepository;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
class NotificationServiceTest {

    @Mock
    private NotificationMessageRepository messageRepository;

    @Mock
    private DeviceTokenRepository tokenRepository;

    @InjectMocks
    private NotificationService notificationService;

    @Test
    void send_withValidRequest_marksSent() {
        when(messageRepository.save(any(NotificationMessage.class))).thenAnswer(invocation -> invocation.getArgument(0));

        NotificationMessage result = notificationService.send(
                new NotificationSendRequest(1L, "TOPUP", NotificationChannel.SMS, "user-1", "credited")
        );

        assertThat(result.getStatus()).isEqualTo(NotificationStatus.SENT);
        assertThat(result.getFailureReason()).isNull();
    }

    @Test
    void registerDevice_updatesExistingToken() {
        DeviceToken existing = new DeviceToken();
        existing.setId(2L);
        existing.setUserId(5L);
        existing.setToken("old");

        when(tokenRepository.findByUserId(5L)).thenReturn(Optional.of(existing));
        when(tokenRepository.save(any(DeviceToken.class))).thenAnswer(invocation -> invocation.getArgument(0));

        DeviceToken result = notificationService.registerDevice(new DeviceTokenRequest(5L, "new-token"));

        assertThat(result.getUserId()).isEqualTo(5L);
        assertThat(result.getToken()).isEqualTo("new-token");
    }

    @Test
    void stats_returnsAggregatedCounts() {
        when(messageRepository.countByStatus(NotificationStatus.SENT)).thenReturn(4L);
        when(messageRepository.countByStatus(NotificationStatus.FAILED)).thenReturn(1L);

        NotificationStatsResponse result = notificationService.stats();

        assertThat(result.sent()).isEqualTo(4L);
        assertThat(result.failed()).isEqualTo(1L);
        assertThat(result.total()).isEqualTo(5L);
    }
}

package com.wallet.rewards.config;

import org.springframework.amqp.core.Binding;
import org.springframework.amqp.core.BindingBuilder;
import org.springframework.amqp.core.DirectExchange;
import org.springframework.amqp.core.Queue;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class RabbitConfig {
    public static final String WALLET_EVENTS_EXCHANGE = "wallet.events.exchange";
    public static final String WALLET_EVENTS_QUEUE = "wallet.events.queue";
    public static final String WALLET_EVENTS_KEY = "wallet.events.key";

    @Bean
    public DirectExchange walletExchange() {
        return new DirectExchange(WALLET_EVENTS_EXCHANGE);
    }

    @Bean
    public Queue walletQueue() {
        return new Queue(WALLET_EVENTS_QUEUE, true);
    }

    @Bean
    public Binding walletBinding(Queue walletQueue, DirectExchange walletExchange) {
        return BindingBuilder.bind(walletQueue).to(walletExchange).with(WALLET_EVENTS_KEY);
    }
}

