}

output "security_group_name" {
  description = "Security Group Name"
  value       = aws_security_group.microservices.name
}

output "ssh_key_name" {
  description = "SSH Key Pair Name"
  value       = aws_key_pair.deployer.key_name
}

output "private_key_path" {
