package com.wallet.transaction.command.controller;

import com.wallet.transaction.command.dto.CommandStatusResponse;
import com.wallet.transaction.command.dto.CreateTransactionCommand;
import com.wallet.transaction.command.handler.TransactionCommandHandler;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/transactions")
public class TransactionCommandController {

    private final TransactionCommandHandler transactionCommandHandler;

    public TransactionCommandController(TransactionCommandHandler transactionCommandHandler) {
        this.transactionCommandHandler = transactionCommandHandler;
    }

    @PostMapping
    public ResponseEntity<CommandStatusResponse> create(@Valid @RequestBody CreateTransactionCommand command) {
        transactionCommandHandler.handle(command);
        return ResponseEntity.accepted().body(
                CommandStatusResponse.accepted(command.idempotencyKey(), "Transaction command accepted")
        );
    }
}

package com.wallet.transaction.command.dto;

public record CommandStatusResponse(
        String status,
        String idempotencyKey,
        String message
) {
    public static CommandStatusResponse accepted(String idempotencyKey, String message) {
        return new CommandStatusResponse("ACCEPTED", idempotencyKey, message);
    }
}

package com.wallet.transaction.command.dto;

import jakarta.validation.constraints.DecimalMin;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;

import java.math.BigDecimal;

public record CreateTransactionCommand(
        @NotNull TransactionCommandType type,
        Long userId,
        Long senderId,
        Long receiverId,
        @NotNull @DecimalMin(value = "0.01") BigDecimal amount,
        Long originalTransactionId,
        @NotBlank String idempotencyKey
) {
}

package com.wallet.transaction.command.dto;

public enum TransactionCommandType {
    TOPUP,
    TRANSFER,
    PAYMENT,
    REFUND
}

package com.wallet.transaction.command.handler;

import com.wallet.transaction.command.dto.CreateTransactionCommand;
import com.wallet.transaction.command.dto.TransactionCommandType;
import com.wallet.transaction.domain.TransactionDomainService;
import com.wallet.transaction.dto.PaymentRequest;
import com.wallet.transaction.dto.RefundRequest;
import com.wallet.transaction.dto.TopupRequest;
import com.wallet.transaction.dto.TransactionResponse;
import com.wallet.transaction.dto.TransferRequest;
import com.wallet.transaction.event.TransactionCreatedEvent;
import com.wallet.transaction.event.TransactionEventPublisher;
import org.springframework.cache.annotation.CacheEvict;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.LinkedHashSet;
import java.util.Set;

@Service
public class TransactionCommandHandler {

    private final TransactionDomainService transactionDomainService;
    private final TransactionEventPublisher transactionEventPublisher;

    public TransactionCommandHandler(TransactionDomainService transactionDomainService,
                                     TransactionEventPublisher transactionEventPublisher) {
        this.transactionDomainService = transactionDomainService;
        this.transactionEventPublisher = transactionEventPublisher;
    }

    @Transactional
    @CacheEvict(cacheNames = "transactionHistory", allEntries = true)
    public void handle(CreateTransactionCommand command) {
        TransactionResponse response = execute(command);
        transactionEventPublisher.publish(new TransactionCreatedEvent(
                command.idempotencyKey(),
                impactedUsers(response).stream().toList(),
                LocalDateTime.now()
        ));
    }

    private TransactionResponse execute(CreateTransactionCommand command) {
        if (command.type() == TransactionCommandType.TOPUP) {
            return transactionDomainService.topup(new TopupRequest(
                    command.userId(),
                    command.amount(),
                    command.idempotencyKey()
            ));
        }

        if (command.type() == TransactionCommandType.TRANSFER) {
            return transactionDomainService.transfer(new TransferRequest(
                    command.senderId(),
                    command.receiverId(),
                    command.amount(),
                    command.idempotencyKey()
            ));
        }

        if (command.type() == TransactionCommandType.PAYMENT) {
            return transactionDomainService.payment(new PaymentRequest(
                    command.senderId(),
                    command.receiverId(),
                    command.amount(),
                    command.idempotencyKey()
            ));
        }

        if (command.type() == TransactionCommandType.REFUND) {
            if (command.originalTransactionId() == null) {
                throw new IllegalArgumentException("originalTransactionId is required for REFUND command");
            }
            return transactionDomainService.refund(new RefundRequest(
                    command.senderId(),
                    command.receiverId(),
                    command.amount(),
                    command.originalTransactionId(),
                    command.idempotencyKey()
            ));
        }

        throw new IllegalArgumentException("Unsupported transaction command type: " + command.type());
    }

    private Set<Long> impactedUsers(TransactionResponse response) {
        Set<Long> users = new LinkedHashSet<>();
        if (response.userId() != null) {
            users.add(response.userId());
        }
        if (response.senderId() != null) {
            users.add(response.senderId());
        }
        if (response.receiverId() != null) {
            users.add(response.receiverId());
        }
        return users;
    }
}

package com.wallet.transaction.config;

import io.swagger.v3.oas.models.Components;
import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.info.Info;
import io.swagger.v3.oas.models.security.SecurityRequirement;
import io.swagger.v3.oas.models.security.SecurityScheme;
import io.swagger.v3.oas.models.servers.Server;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.util.List;

@Configuration
public class OpenApiConfig {

    private static final String BEARER_AUTH = "bearerAuth";

    @Bean
    public OpenAPI transactionServiceOpenAPI() {
        return new OpenAPI()
                .info(new Info()
                        .title("API Gateway - Transaction Service API")
                        .version("1.0")
                        .description("API documentation for ledger-first transactions, history, and idempotent financial operations"))
                .components(new Components().addSecuritySchemes(BEARER_AUTH,
                        new SecurityScheme()
                                .name(BEARER_AUTH)
                                .type(SecurityScheme.Type.HTTP)
                                .scheme("bearer")
                                .bearerFormat("JWT")))
                .addSecurityItem(new SecurityRequirement().addList(BEARER_AUTH))
                .servers(List.of(new Server().url("/")));
    }
}

package com.wallet.transaction.config;

import org.springframework.amqp.core.Binding;
import org.springframework.amqp.core.BindingBuilder;
import org.springframework.amqp.core.DirectExchange;
import org.springframework.amqp.core.Queue;
import org.springframework.amqp.support.converter.Jackson2JsonMessageConverter;
import org.springframework.amqp.support.converter.MessageConverter;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class RabbitConfig {
    public static final String WALLET_EVENTS_EXCHANGE = "wallet.events.exchange";
    public static final String WALLET_EVENTS_KEY = "wallet.events.key";
    public static final String WALLET_EVENTS_QUEUE = "wallet.events.queue";

    public static final String CQRS_EXCHANGE = "cqrs.events.exchange";
    public static final String TRANSACTION_EVENTS_KEY = "transaction.events";
    public static final String TRANSACTION_EVENTS_QUEUE = "transaction.events";

    @Bean
    public DirectExchange walletExchange() {
        return new DirectExchange(WALLET_EVENTS_EXCHANGE, true, false);
    }

    @Bean
    public Queue walletEventsQueue() {
        return new Queue(WALLET_EVENTS_QUEUE, true);
    }

    @Bean
    public Binding walletEventsBinding(Queue walletEventsQueue, DirectExchange walletExchange) {
        return BindingBuilder.bind(walletEventsQueue)
                .to(walletExchange)
                .with(WALLET_EVENTS_KEY);
    }

    @Bean
    public DirectExchange transactionCqrsExchange() {
        return new DirectExchange(CQRS_EXCHANGE, true, false);
    }

    @Bean
    public Queue transactionEventsQueue() {
        return new Queue(TRANSACTION_EVENTS_QUEUE, true);
    }

    @Bean
    public Binding transactionEventsBinding(Queue transactionEventsQueue, DirectExchange transactionCqrsExchange) {
        return BindingBuilder.bind(transactionEventsQueue)
                .to(transactionCqrsExchange)
                .with(TRANSACTION_EVENTS_KEY);
    }

    @Bean
    public MessageConverter transactionRabbitMessageConverter() {
        return new Jackson2JsonMessageConverter();
    }

    @Bean(name = "rabbitTemplate")
    public org.springframework.amqp.rabbit.core.RabbitTemplate rabbitTemplate(
            org.springframework.amqp.rabbit.connection.ConnectionFactory connectionFactory) {
        org.springframework.amqp.rabbit.core.RabbitTemplate template = 
                new org.springframework.amqp.rabbit.core.RabbitTemplate(connectionFactory);
        template.setMessageConverter(transactionRabbitMessageConverter());
        return template;
    }
}

package com.wallet.transaction.config;

import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.cache.CacheManager;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.data.redis.cache.RedisCacheConfiguration;
import org.springframework.data.redis.cache.RedisCacheManager;
import org.springframework.data.redis.connection.RedisConnectionFactory;
import org.springframework.data.redis.serializer.GenericJackson2JsonRedisSerializer;
import org.springframework.data.redis.serializer.RedisSerializationContext;

import java.time.Duration;

@Configuration
public class RedisConfig {

    @Bean
    public CacheManager cacheManager(RedisConnectionFactory connectionFactory, ObjectMapper objectMapper) {
        GenericJackson2JsonRedisSerializer serializer = new GenericJackson2JsonRedisSerializer(objectMapper);
        RedisCacheConfiguration configuration = RedisCacheConfiguration.defaultCacheConfig()
                .serializeValuesWith(RedisSerializationContext.SerializationPair.fromSerializer(serializer))
                .entryTtl(Duration.ofMinutes(5))
                .disableCachingNullValues();

        return RedisCacheManager.builder(connectionFactory)
                .cacheDefaults(configuration)
                .build();
    }
}

package com.wallet.transaction.controller;

import com.wallet.transaction.dto.DisputeCreateRequest;
import com.wallet.transaction.dto.DisputeResolveRequest;
