        Long userId,
        BigDecimal balance
) {
}

package com.wallet.wallet.query.dto;

import com.wallet.wallet.entity.LedgerEntry;

import java.math.BigDecimal;
import java.time.LocalDateTime;

public record WalletHistoryItemView(
        Long id,
        String type,
        BigDecimal amount,
        String reference,
        LocalDateTime createdAt
) {
    public static WalletHistoryItemView fromEntity(LedgerEntry entry) {
        return new WalletHistoryItemView(
                entry.getId(),
                entry.getType(),
                entry.getAmount(),
                entry.getReference(),
                entry.getCreatedAt()
        );
    }
}

package com.wallet.wallet.query.handler;

import com.wallet.wallet.config.RabbitConfig;
import com.wallet.wallet.event.WalletUpdatedEvent;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.cache.Cache;
import org.springframework.cache.CacheManager;
import org.springframework.stereotype.Component;

@Component
public class WalletCacheInvalidationListener {

    private final CacheManager cacheManager;

    public WalletCacheInvalidationListener(CacheManager cacheManager) {
        this.cacheManager = cacheManager;
    }

    @RabbitListener(queues = RabbitConfig.WALLET_CQRS_EVENTS_QUEUE)
    public void onWalletUpdated(WalletUpdatedEvent event) {
        Cache balanceCache = cacheManager.getCache("walletBalance");
        Cache historyCache = cacheManager.getCache("walletHistory");

        if (event.impactedUserIds() == null) {
            return;
        }

        for (Long userId : event.impactedUserIds()) {
            if (userId == null) {
                continue;
            }
            if (balanceCache != null) {
                balanceCache.evict(userId);
            }
            if (historyCache != null) {
                historyCache.evict(userId);
            }
        }
    }
}

package com.wallet.wallet.query.handler;

import com.wallet.wallet.query.dto.WalletBalanceView;
import com.wallet.wallet.query.dto.WalletHistoryItemView;
import com.wallet.wallet.repository.LedgerEntryRepository;
import com.wallet.wallet.repository.WalletAccountRepository;
import org.springframework.cache.annotation.Cacheable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.List;

@Service
public class WalletQueryHandler {

    private final WalletAccountRepository walletAccountRepository;
    private final LedgerEntryRepository ledgerEntryRepository;

    public WalletQueryHandler(WalletAccountRepository walletAccountRepository,
                              LedgerEntryRepository ledgerEntryRepository) {
        this.walletAccountRepository = walletAccountRepository;
        this.ledgerEntryRepository = ledgerEntryRepository;
    }

    @Transactional(readOnly = true)
    @Cacheable(cacheNames = "walletBalance", key = "#userId")
    public WalletBalanceView getWallet(Long userId) {
        BigDecimal balance = walletAccountRepository.findByUserId(userId)
                .map(account -> account.getBalance())
                .orElse(BigDecimal.ZERO);
        return new WalletBalanceView(userId, balance);
    }

    @Transactional(readOnly = true)
    @Cacheable(cacheNames = "walletHistory", key = "#userId")
    public List<WalletHistoryItemView> getWalletHistory(Long userId) {
        return ledgerEntryRepository.findByUserIdOrderByCreatedAtDesc(userId)
                .stream()
                .map(WalletHistoryItemView::fromEntity)
                .toList();
    }
}

package com.wallet.wallet.repository;

import com.wallet.wallet.entity.LedgerEntry;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;

public interface LedgerEntryRepository extends JpaRepository<LedgerEntry, Long> {
    List<LedgerEntry> findByUserIdOrderByCreatedAtDesc(Long userId);

    @Query("select coalesce(sum(l.amount), 0) from LedgerEntry l where l.userId = :userId and l.type = :type and l.createdAt between :from and :to")
    BigDecimal sumByUserAndTypeAndCreatedAtBetween(@Param("userId") Long userId,
                                                    @Param("type") String type,
                                                    @Param("from") LocalDateTime from,
                                                    @Param("to") LocalDateTime to);

    long countByUserIdAndTypeAndCreatedAtBetween(Long userId, String type, LocalDateTime from, LocalDateTime to);
}

